<div class="mb-6"><h3 class="text-lg font-semibold text-gray-800 dark:text-white">Blog</h3></div><div class="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden"><div class="overflow-x-auto"><table class="w-full"><thead><tr class="bg-gray-50 dark:bg-gray-900/50"><th class="px-4 py-3 text-left text-xs font-semibold text-gray-500 uppercase">Título</th><th class="px-4 py-3 text-left text-xs font-semibold text-gray-500 uppercase">Status</th></tr></thead><tbody class="divide-y divide-gray-100 dark:divide-gray-700"><?php foreach ($posts as $row): ?><tr class="hover:bg-gray-50 dark:hover:bg-gray-900/30"><td class="px-4 py-3 text-sm text-gray-600 dark:text-gray-400"><?= htmlspecialchars($row['title'] ?? '—') ?></td><td class="px-4 py-3 text-sm text-gray-600 dark:text-gray-400"><?= htmlspecialchars($row['status'] ?? '—') ?></td></tr><?php endforeach; ?><?php if (empty($posts)): ?><tr><td colspan="2" class="px-4 py-12 text-center text-gray-500">Nenhum registro encontrado.</td></tr><?php endif; ?></tbody></table></div></div>